  5→//! Nominate command - create a new Heat
  6→//!
  7→//! This module provides the Args struct and handler for the jjx_nominate command.
  8→
  9→use std::fmt::Write;
 10→use std::path::PathBuf;
 11→use std::collections::BTreeMap;
 12→
 13→use crate::jjrf_favor::{jjrf_Firemark as Firemark};
 14→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_NominateArgs as LibNominateArgs};
 15→use crate::jjrc_core::jjrc_timestamp_from_env;
 16→use crate::jjrn_notch::{jjrn_HeatAction as HeatAction, jjrn_format_heat_message as format_heat_message};
 17→
 18→/// Arguments for jjx_nominate command
 19→#[derive(clap::Args, Debug)]
 20→pub struct jjrx_NominateArgs {
 21→    /// Path to the Gallops JSON file
 22→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
 23→    pub file: PathBuf,
 24→
 25→    /// Kebab-case display name for the Heat
 26→    #[arg(long, short = 's')]
 27→    pub silks: String,
 28→}
 29→
 30→/// Handler for jjx_nominate command
 31→pub fn jjrx_run_nominate(args: jjrx_NominateArgs) -> (i32, String) {
 32→    use std::path::Path;
 33→    let mut buf = String::new();
 34→
 35→    // Acquire lock FIRST - fail fast if another operation is in progress
 36→    let lock = match vvc::vvcc_CommitLock::vvcc_acquire() {
 37→        Ok(l) => l,
 38→        Err(e) => {
 39→            jjbuf!(buf, "jjx_nominate: error: {}", e);
 40→            return (1, buf);
 41→        }
 42→    };
 43→
 44→    let mut gallops = if args.file.exists() {
 45→        match Gallops::jjrg_load(&args.file) {
 46→            Ok(g) => g,
 47→            Err(e) => {
 48→                jjbuf!(buf, "jjx_nominate: error loading Gallops: {}", e);
 49→                return (1, buf);
 50→            }
 51→        }
 52→    } else {
 53→        if let Some(parent) = args.file.parent() {
 54→            if let Err(e) = std::fs::create_dir_all(parent) {
 55→                jjbuf!(buf, "jjx_nominate: error creating directory: {}", e);
 56→                return (1, buf);
 57→            }
 58→        }
 59→        Gallops {
 60→            next_heat_seed: "AA".to_string(),
 61→            heat_order: vec![],
 62→            heats: BTreeMap::new(),
 63→        }
 64→    };
 65→
 66→    let base_path = args.file.parent()
 67→        .and_then(|p| p.parent())
 68→        .and_then(|p| p.parent())
 69→        .unwrap_or(Path::new("."));
 70→
 71→    let silks = args.silks.clone();
 72→    let nominate_args = LibNominateArgs {
 73→        silks: args.silks,
 74→        created: jjrc_timestamp_from_env(),
 75→    };
 76→
 77→    match gallops.jjrg_nominate(nominate_args, base_path) {
 78→        Ok(result) => {
 79→            let fm = Firemark::jjrf_parse(&result.firemark).expect("nominate returned invalid firemark");
 80→            let message = format_heat_message(&fm, HeatAction::Nominate, &silks);
 81→
 82→            match crate::jjri_io::jjri_persist(&lock, &gallops, &args.file, &fm, message, 50000) {
 83→                Ok(hash) => {
 84→                    jjbuf!(buf, "jjx_nominate: committed {}", &hash[..8]);
 85→                }
 86→                Err(e) => {
 87→                    jjbuf!(buf, "jjx_nominate: error: {}", e);
 88→                    return (1, buf);
 89→                }
 90→            }
 91→
 92→            let _ = writeln!(buf, "{}", result.firemark);
 93→            (0, buf)
 94→        }
 95→        Err(e) => {
 96→            jjbuf!(buf, "jjx_nominate: error: {}", e);
 97→            (1, buf)
 98→        }
 99→    }
100→    // lock released here
101→}
102→
103→#[cfg(test)]
104→mod tests {
105→    use super::*;
106→    use crate::jjrg_gallops::*;
107→    use crate::jjtu_testdir::JjkTestDir;
108→    use std::collections::BTreeMap;
109→
110→    #[test]
111→    fn test_nominate_appends_to_heat_order() {
112→        let td = JjkTestDir::new("jjk_test_nominate_appends_to_heat_order");
113→
114→        let mut gallops = jjrg_Gallops {
115→            next_heat_seed: "AA".to_string(),
116→            heat_order: vec![],
117→            heats: BTreeMap::new(),
118→        };
119→        let args = jjrg_NominateArgs {
120→            silks: "test-heat".to_string(),
121→            created: "260101".to_string(),
122→        };
123→        let result = gallops.jjrg_nominate(args, td.path()).unwrap();
124→        assert!(gallops.heat_order.contains(&result.firemark),
125→            "heat_order should contain the new firemark after nominate");
126→    }
127→}
