  5→//! Rail command - reorder Paces within a Heat
  6→//!
  7→//! Supports two modes:
  8→//! - Order mode: replace entire sequence with provided order array
  9→//! - Move mode: relocate a single pace using positioning flags
 10→
 11→use clap::Args;
 12→use std::path::PathBuf;
 13→
 14→use crate::jjrf_favor::jjrf_Firemark as Firemark;
 15→use crate::jjrg_gallops::jjrg_Gallops as Gallops;
 16→
 17→/// Arguments for jjx_rail command
 18→#[derive(Args, Debug)]
 19→pub struct jjrrl_RailArgs {
 20→    /// Path to the Gallops JSON file
 21→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
 22→    pub file: PathBuf,
 23→
 24→    /// Target Heat identity (Firemark)
 25→    pub firemark: String,
 26→
 27→    /// Legacy positional args - rejected at runtime
 28→    #[arg(trailing_var_arg = true)]
 29→    pub order: Vec<String>,
 30→
 31→    // Move mode arguments
 32→
 33→    /// Coronet to relocate within order - triggers move mode
 34→    #[arg(long, short = 'm')]
 35→    pub r#move: Option<String>,
 36→
 37→    /// Move before specified Coronet
 38→    #[arg(long, conflicts_with_all = ["after", "first", "last"])]
 39→    pub before: Option<String>,
 40→
 41→    /// Move after specified Coronet
 42→    #[arg(long, conflicts_with_all = ["before", "first", "last"])]
 43→    pub after: Option<String>,
 44→
 45→    /// Move to beginning of order
 46→    #[arg(long, conflicts_with_all = ["before", "after", "last"])]
 47→    pub first: bool,
 48→
 49→    /// Move to end of order
 50→    #[arg(long, conflicts_with_all = ["before", "after", "first"])]
 51→    pub last: bool,
 52→}
 53→
 54→/// Execute rail command - reorder Paces within a Heat
 55→pub fn jjrrl_run_rail(args: jjrrl_RailArgs) -> (i32, String) {
 56→    use std::fmt::Write;
 57→    use crate::jjrg_gallops::jjrg_RailArgs as LibRailArgs;
 58→    use crate::jjrn_notch::{jjrn_HeatAction, jjrn_format_heat_message};
 59→
 60→    let mut buf = String::new();
 61→
 62→    // Acquire lock FIRST - fail fast if another operation is in progress
 63→    let lock = match vvc::vvcc_CommitLock::vvcc_acquire() {
 64→        Ok(l) => l,
 65→        Err(e) => {
 66→            jjbuf!(buf, "jjx_rail: error: {}", e);
 67→            return (1, buf);
 68→        }
 69→    };
 70→
 71→    let order: Vec<String> = if args.order.len() == 1 && args.order[0].starts_with('[') {
 72→        match serde_json::from_str(&args.order[0]) {
 73→            Ok(v) => v,
 74→            Err(_) => args.order.clone(),
 75→        }
 76→    } else {
 77→        args.order.clone()
 78→    };
 79→
 80→    let mut gallops = match Gallops::jjrg_load(&args.file) {
 81→        Ok(g) => g,
 82→        Err(e) => {
 83→            jjbuf!(buf, "jjx_rail: error loading Gallops: {}", e);
 84→            return (1, buf);
 85→        }
 86→    };
 87→
 88→    let firemark = args.firemark.clone();
 89→    let move_coronet = args.r#move.clone();
 90→    let move_before = args.before.clone();
 91→    let move_after = args.after.clone();
 92→    let move_first = args.first;
 93→    let move_last = args.last;
 94→
 95→    // Capture old order for no-op detection
 96→    let fm = Firemark::jjrf_parse(&firemark).expect("rail given invalid firemark");
 97→    let old_order: Vec<String> = gallops.heats.get(&fm.jjrf_display())
 98→        .map(|h| h.order.clone())
 99→        .unwrap_or_default();
100→
101→    let rail_args = LibRailArgs {
102→        firemark: args.firemark,
103→        order,
104→        move_coronet: args.r#move,
105→        before: args.before,
106→        after: args.after,
107→        first: args.first,
108→        last: args.last,
109→    };
110→
111→    match gallops.jjrg_rail(rail_args) {
112→        Ok(new_order) => {
113→            // No-op detection: if order unchanged, exit 0 with message
114→            if new_order == old_order {
115→                let position = if move_first { "first" }
116→                    else if move_last { "last" }
117→                    else if move_before.is_some() { "requested position" }
118→                    else if move_after.is_some() { "requested position" }
119→                    else { "requested position" };
120→                let coronet_display = move_coronet.as_deref().unwrap_or("pace");
121→                jjbuf!(buf, "jjx_rail: no change — {} is already {}", coronet_display, position);
122→                for coronet in new_order {
123→                    let _ = writeln!(buf, "{}", coronet);
124→                }
125→                return (0, buf);
126→            }
127→
128→            // Compute descriptive subject for commit message
129→            let subject = if let Some(ref moved) = move_coronet {
130→                // Move mode: describe where the pace was moved
131→                let target = if move_first { "to first".to_string() }
132→                    else if move_last { "to last".to_string() }
133→                    else if let Some(ref b) = move_before { format!("before {}", b) }
134→                    else if let Some(ref a) = move_after { format!("after {}", a) }
135→                    else { "???".to_string() };
136→                format!("moved {} {}", moved, target)
137→            } else {
138→                // Order mode: list the new order
139→                format!("order: {}", new_order.join(", "))
140→            };
141→
142→            let message = jjrn_format_heat_message(&fm, jjrn_HeatAction::Rail, &subject);
143→
144→            match crate::jjri_io::jjri_persist(&lock, &gallops, &args.file, &fm, message, 50000) {
145→                Ok(hash) => {
146→                    jjbuf!(buf, "jjx_rail: committed {}", &hash[..8]);
147→                }
148→                Err(e) => {
149→                    jjbuf!(buf, "jjx_rail: error: {}", e);
150→                    return (1, buf);
151→                }
152→            }
153→
154→            for coronet in new_order {
155→                let _ = writeln!(buf, "{}", coronet);
156→            }
157→            (0, buf)
158→        }
159→        Err(e) => {
160→            jjbuf!(buf, "jjx_rail: error: {}", e);
161→            (1, buf)
162→        }
163→    }
164→    // lock released here
165→}
