  5→//! Draft command - move a Pace from one Heat to another
  6→//!
  7→//! Implements the jjx_draft subcommand and related structures.
  8→
  9→use clap::Args;
 10→use std::fmt::Write;
 11→use std::path::PathBuf;
 12→
 13→use crate::jjrf_favor::jjrf_Firemark as Firemark;
 14→use crate::jjrg_gallops::jjrg_Gallops as Gallops;
 15→use crate::jjri_io::jjri_paddock_path;
 16→use crate::jjrn_notch::{jjrn_HeatAction as HeatAction, jjrn_format_heat_message as format_heat_message};
 17→
 18→/// Arguments for jjx_draft command
 19→#[derive(Args, Debug)]
 20→pub struct jjrdr_DraftArgs {
 21→    /// Path to the Gallops JSON file
 22→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
 23→    pub file: PathBuf,
 24→
 25→    /// Pace identity to move (Coronet)
 26→    pub coronet: String,
 27→
 28→    /// Destination Heat identity (Firemark)
 29→    #[arg(long)]
 30→    pub to: String,
 31→
 32→    /// Insert before specified Coronet in destination
 33→    #[arg(long, conflicts_with_all = ["after", "first"])]
 34→    pub before: Option<String>,
 35→
 36→    /// Insert after specified Coronet in destination
 37→    #[arg(long, conflicts_with_all = ["before", "first"])]
 38→    pub after: Option<String>,
 39→
 40→    /// Insert at beginning of destination Heat
 41→    #[arg(long, conflicts_with_all = ["before", "after"])]
 42→    pub first: bool,
 43→}
 44→
 45→/// Handler function for draft command
 46→pub fn jjrdr_run_draft(args: jjrdr_DraftArgs) -> (i32, String) {
 47→    use crate::jjrg_gallops::jjrg_DraftArgs as LibDraftArgs;
 48→    let mut buf = String::new();
 49→
 50→    // Acquire lock FIRST - fail fast if another operation is in progress
 51→    let lock = match vvc::vvcc_CommitLock::vvcc_acquire() {
 52→        Ok(l) => l,
 53→        Err(e) => {
 54→            jjbuf!(buf, "jjx_draft: error: {}", e);
 55→            return (1, buf);
 56→        }
 57→    };
 58→
 59→    let mut gallops = match Gallops::jjrg_load(&args.file) {
 60→        Ok(g) => g,
 61→        Err(e) => {
 62→            jjbuf!(buf, "jjx_draft: error loading Gallops: {}", e);
 63→            return (1, buf);
 64→        }
 65→    };
 66→
 67→    let coronet = args.coronet.clone();
 68→    let to = args.to.clone();
 69→    let draft_args = LibDraftArgs {
 70→        coronet: args.coronet,
 71→        to: args.to,
 72→        before: args.before,
 73→        after: args.after,
 74→        first: args.first,
 75→    };
 76→
 77→    match gallops.jjrg_draft(draft_args) {
 78→        Ok(result) => {
 79→            // Save gallops
 80→            if let Err(e) = gallops.jjrg_save(&args.file) {
 81→                jjbuf!(buf, "jjx_draft: error saving Gallops: {}", e);
 82→                return (1, buf);
 83→            }
 84→
 85→            // Commit using machine_commit - draft affects source and dest paddocks
 86→            // Parse both firemarks to get paddock paths
 87→            let src_coronet = crate::jjrf_favor::jjrf_Coronet::jjrf_parse(&coronet)
 88→                .expect("draft given invalid source coronet");
 89→            let src_fm = src_coronet.jjrf_parent_firemark();
 90→            let dest_fm = Firemark::jjrf_parse(&to).expect("draft given invalid destination firemark");
 91→
 92→            let gallops_path = args.file.to_string_lossy().to_string();
 93→            let src_paddock_path = jjri_paddock_path(src_fm.jjrf_as_str());
 94→            let dest_paddock_path = jjri_paddock_path(dest_fm.jjrf_as_str());
 95→
 96→            let commit_args = vvc::vvcm_CommitArgs {
 97→                files: vec![
 98→                    gallops_path,
 99→                    src_paddock_path,
100→                    dest_paddock_path,
101→                ],
102→                message: format_heat_message(&dest_fm, HeatAction::Draft, &format!("{} → {}", coronet, result.new_coronet)),
103→                size_limit: 50000,
104→                warn_limit: 30000,
105→            };
106→
107→            match vvc::machine_commit(&lock, &commit_args) {
108→                Ok(hash) => {
109→                    jjbuf!(buf, "jjx_draft: committed {}", &hash[..8]);
110→                }
111→                Err(e) => {
112→                    jjbuf!(buf, "jjx_draft: commit warning: {}", e);
113→                }
114→            }
115→
116→            let _ = writeln!(buf, "{}", result.new_coronet);
117→            (0, buf)
118→        }
119→        Err(e) => {
120→            jjbuf!(buf, "jjx_draft: error: {}", e);
121→            (1, buf)
122→        }
123→    }
124→    // lock released here
125→}
