 5→//! Get spec command - Extract spec text for a pace
 6→//!
 7→//! Implements the `jjx_get_spec` command which retrieves and outputs the raw
 8→//! specification text for a single pace.
 9→
10→use std::fmt::Write;
11→use std::path::PathBuf;
12→use clap::Args;
13→
14→use crate::jjrf_favor::jjrf_Coronet as Coronet;
15→use crate::jjrg_gallops::jjrg_Gallops as Gallops;
16→
17→/// Arguments for jjx_get_spec command
18→#[derive(Args, Debug)]
19→pub struct jjrgs_GetSpecArgs {
20→    /// Path to the Gallops JSON file
21→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
22→    pub file: PathBuf,
23→
24→    /// Target Pace identity (Coronet)
25→    pub coronet: String,
26→}
27→
28→/// Run the get_spec command - output raw spec text
29→pub fn jjrgs_run_get_spec(args: jjrgs_GetSpecArgs) -> (i32, String) {
30→    let mut buf = String::new();
31→
32→    let coronet = match Coronet::jjrf_parse(&args.coronet) {
33→        Ok(c) => c,
34→        Err(e) => {
35→            jjbuf!(buf, "jjx_get_spec: error: {}", e);
36→            return (1, buf);
37→        }
38→    };
39→
40→    let gallops = match Gallops::jjrg_load(&args.file) {
41→        Ok(g) => g,
42→        Err(e) => {
43→            jjbuf!(buf, "jjx_get_spec: error: {}", e);
44→            return (1, buf);
45→        }
46→    };
47→
48→    // Extract parent firemark and locate heat
49→    let firemark = coronet.jjrf_parent_firemark();
50→    let heat_key = firemark.jjrf_display();
51→    let heat = match gallops.heats.get(&heat_key) {
52→        Some(h) => h,
53→        None => {
54→            jjbuf!(buf, "jjx_get_spec: error: Heat '{}' not found", heat_key);
55→            return (1, buf);
56→        }
57→    };
58→
59→    // Locate pace
60→    let coronet_key = coronet.jjrf_display();
61→    let pace = match heat.paces.get(&coronet_key) {
62→        Some(p) => p,
63→        None => {
64→            jjbuf!(buf, "jjx_get_spec: error: Pace '{}' not found in Heat '{}'", coronet_key, heat_key);
65→            return (1, buf);
66→        }
67→    };
68→
69→    // Output tacks[0].text (current spec)
70→    if let Some(tack) = pace.tacks.first() {
71→        let _ = write!(buf, "{}", tack.text);
72→        (0, buf)
73→    } else {
74→        jjbuf!(buf, "jjx_get_spec: error: Pace '{}' has no tacks", coronet_key);
75→        (1, buf)
76→    }
77→}
