  5→//! Scout command - Search across heats and paces with regex
  6→
  7→use clap::Args;
  8→use std::fmt::Write;
  9→use std::path::PathBuf;
 10→use regex::Regex;
 11→use std::fs;
 12→
 13→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_PaceState as PaceState};
 14→
 15→/// Arguments for jjx_scout command
 16→#[derive(Args, Debug)]
 17→pub struct jjrsc_ScoutArgs {
 18→    /// Path to the Gallops JSON file
 19→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
 20→    pub file: PathBuf,
 21→
 22→    /// Regex pattern to search for
 23→    pub pattern: String,
 24→
 25→    /// Limit to actionable paces only (rough/bridled)
 26→    #[arg(long)]
 27→    pub actionable: bool,
 28→}
 29→
 30→/// Run the scout command - regex search across heats/paces
 31→pub fn jjrsc_run_scout(args: jjrsc_ScoutArgs) -> (i32, String) {
 32→    use regex::RegexBuilder;
 33→
 34→    let mut buf = String::new();
 35→
 36→    let gallops = match Gallops::jjrg_load(&args.file) {
 37→        Ok(g) => g,
 38→        Err(e) => {
 39→            jjbuf!(buf, "jjx_scout: error: {}", e);
 40→            return (1, buf);
 41→        }
 42→    };
 43→
 44→    // Build case-insensitive regex
 45→    let re = match RegexBuilder::new(&args.pattern)
 46→        .case_insensitive(true)
 47→        .build()
 48→    {
 49→        Ok(r) => r,
 50→        Err(e) => {
 51→            jjbuf!(buf, "jjx_scout: error: invalid regex pattern: {}", e);
 52→            return (1, buf);
 53→        }
 54→    };
 55→
 56→    // Track which heats have matches (for group headers)
 57→    let mut current_heat_key: Option<String> = None;
 58→
 59→    // Iterate all heats (racing, stabled, retired)
 60→    for (heat_key, heat) in &gallops.heats {
 61→        // Search each pace in order
 62→        for coronet_key in &heat.order {
 63→            if let Some(pace) = heat.paces.get(coronet_key) {
 64→                if let Some(tack) = pace.tacks.first() {
 65→                    // Apply actionable filter if requested
 66→                    if args.actionable {
 67→                        match tack.state {
 68→                            PaceState::Rough | PaceState::Bridled => {},
 69→                            _ => continue,
 70→                        }
 71→                    }
 72→
 73→                    // Search: silks, spec (tack text), direction, paddock content
 74→                    // Use owned strings to avoid lifetime issues
 75→                    let mut match_result: Option<(String, String)> = None;
 76→
 77→                    if re.is_match(&tack.silks) {
 78→                        match_result = Some(("silks".to_string(), tack.silks.clone()));
 79→                    } else if re.is_match(&tack.text) {
 80→                        match_result = Some(("spec".to_string(), tack.text.clone()));
 81→                    } else if let Some(ref direction) = tack.direction {
 82→                        if re.is_match(direction) {
 83→                            match_result = Some(("direction".to_string(), direction.clone()));
 84→                        }
 85→                    } else {
 86→                        // Search paddock content
 87→                        let paddock_path = std::path::Path::new(&heat.paddock_file);
 88→                        if let Ok(content) = fs::read_to_string(paddock_path) {
 89→                            if re.is_match(&content) {
 90→                                match_result = Some(("paddock".to_string(), content));
 91→                            }
 92→                        }
 93→                    }
 94→
 95→                    // If we found a match, output it
 96→                    if let Some((field_name, field_content)) = match_result {
 97→                        // Print heat header if this is a new heat
 98→                        if current_heat_key.as_ref() != Some(heat_key) {
 99→                            let _ = writeln!(buf, "{} {}", heat_key, heat.silks);
100→                            current_heat_key = Some(heat_key.clone());
101→                        }
102→
103→                        // Print pace line
104→                        let state_str = zjrsc_pace_state_str(&tack.state);
105→                        let _ = writeln!(buf, "  {} [{}] {}", coronet_key, state_str, tack.silks);
106→
107→                        // Print match line with context (extract ~60 chars around match)
108→                        let match_excerpt = zjrsc_extract_match_context(&field_content, &re);
109→                        let _ = writeln!(buf, "    {}: {}", field_name, match_excerpt);
110→                    }
111→                }
112→            }
113→        }
114→    }
115→
116→    (0, buf)
117→}
118→
119→/// Helper to convert PaceState to display string
120→pub(crate) fn zjrsc_pace_state_str(state: &PaceState) -> &'static str {
121→    match state {
122→        PaceState::Rough => "rough",
123→        PaceState::Bridled => "bridled",
124→        PaceState::Complete => "complete",
125→        PaceState::Abandoned => "abandoned",
126→    }
127→}
128→
129→/// Extract context around the first regex match in content
130→pub(crate) fn zjrsc_extract_match_context(content: &str, re: &Regex) -> String {
131→    if let Some(mat) = re.find(content) {
132→        let start = mat.start();
133→        let end = mat.end();
134→
135→        // Find context window (30 chars before, 30 chars after)
136→        let context_before = 30;
137→        let context_after = 30;
138→
139→        // Snap window boundaries to valid UTF-8 char boundaries
140→        let mut window_start = start.saturating_sub(context_before);
141→        while !content.is_char_boundary(window_start) {
142→            window_start -= 1;
143→        }
144→
145→        let mut window_end = (end + context_after).min(content.len());
146→        while !content.is_char_boundary(window_end) {
147→            window_end += 1;
148→        }
149→        let window_end = window_end.min(content.len());
150→
151→        let mut excerpt = String::new();
152→        if window_start > 0 {
153→            excerpt.push_str("...");
154→        }
155→        excerpt.push_str(&content[window_start..window_end]);
156→        if window_end < content.len() {
157→            excerpt.push_str("...");
158→        }
159→
160→        // Replace newlines with spaces for single-line display
161→        excerpt.replace('\n', " ").replace('\r', "")
162→    } else {
163→        // Shouldn't happen, but fallback to truncated content
164→        let truncated = content.chars().take(60).collect::<String>();
165→        if content.len() > 60 {
166→            format!("{}...", truncated)
167→        } else {
168→            truncated
169→        }
170→    }
171→}
