 44→    use crate::jjrg_gallops::jjrg_SlateArgs as LibSlateArgs;
 45→    let mut buf = String::new();
 46→
 47→    // Acquire lock FIRST - fail fast if another operation is in progress
 48→    let lock = match vvc::vvcc_CommitLock::vvcc_acquire() {
 49→        Ok(l) => l,
 50→        Err(e) => {
 51→            jjbuf!(buf, "jjx_slate: error: {}", e);
