 80→            let message = format_heat_message(&fm, HeatAction::Slate, &silks);
 81→
 82→            match crate::jjri_io::jjri_persist(&lock, &gallops, &args.file, &fm, message, 50000) {
 83→                Ok(_hash) => {}
