  5→//! Nominate command - create a new Heat
  6→//!
  7→//! This module provides the Args struct and handler for the jjx_nominate command.
  8→
  9→use std::path::PathBuf;
 10→use std::collections::BTreeMap;
 11→
 12→use vvc::{vvco_out, vvco_err, vvco_Output};
 13→
 14→use crate::jjrf_favor::{jjrf_Firemark as Firemark};
 15→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_NominateArgs as LibNominateArgs};
 16→use crate::jjrc_core::jjrc_timestamp_from_env;
 17→use crate::jjrn_notch::{jjrn_HeatAction as HeatAction, jjrn_format_heat_message as format_heat_message};
 18→
 19→/// Arguments for jjx_nominate command
 20→#[derive(clap::Args, Debug)]
 21→pub struct jjrx_NominateArgs {
 22→    /// Path to the Gallops JSON file
 23→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
 24→    pub file: PathBuf,
 25→
 26→    /// Kebab-case display name for the Heat
 27→    #[arg(long, short = 's')]
 28→    pub silks: String,
 29→}
 30→
 31→/// Handler for jjx_nominate command
 32→pub fn jjrx_run_nominate(args: jjrx_NominateArgs) -> (i32, String) {
 33→    use std::path::Path;
 34→    let mut output = vvco_Output::buffer();
 35→
 36→    // Acquire lock FIRST - fail fast if another operation is in progress
 37→    let lock = match vvc::vvcc_CommitLock::vvcc_acquire() {
 38→        Ok(l) => l,
 39→        Err(e) => {
 40→            vvco_err!(output, "jjx_nominate: error: {}", e);
 41→            return (1, output.vvco_finish());
 42→        }
 43→    };
 44→
 45→    let mut gallops = if args.file.exists() {
 46→        match Gallops::jjrg_load(&args.file) {
 47→            Ok(g) => g,
 48→            Err(e) => {
 49→                vvco_err!(output, "jjx_nominate: error loading Gallops: {}", e);
 50→                return (1, output.vvco_finish());
 51→            }
 52→        }
 53→    } else {
 54→        if let Some(parent) = args.file.parent() {
 55→            if let Err(e) = std::fs::create_dir_all(parent) {
 56→                vvco_err!(output, "jjx_nominate: error creating directory: {}", e);
 57→                return (1, output.vvco_finish());
 58→            }
 59→        }
 60→        Gallops {
 61→            next_heat_seed: "AA".to_string(),
 62→            heat_order: vec![],
 63→            heats: BTreeMap::new(),
 64→        }
 65→    };
 66→
 67→    let base_path = args.file.parent()
 68→        .and_then(|p| p.parent())
 69→        .and_then(|p| p.parent())
 70→        .unwrap_or(Path::new("."));
 71→
 72→    let silks = args.silks.clone();
 73→    let nominate_args = LibNominateArgs {
 74→        silks: args.silks,
 75→        created: jjrc_timestamp_from_env(),
 76→    };
 77→
 78→    match gallops.jjrg_nominate(nominate_args, base_path) {
 79→        Ok(result) => {
 80→            let fm = Firemark::jjrf_parse(&result.firemark).expect("nominate returned invalid firemark");
 81→            let message = format_heat_message(&fm, HeatAction::Nominate, &silks);
 82→
 83→            match crate::jjri_io::jjri_persist(&lock, &gallops, &args.file, &fm, message, 50000, &mut output) {
 84→                Ok(hash) => {
 85→                    vvco_out!(output, "jjx_nominate: committed {}", &hash[..8]);
 86→                }
 87→                Err(e) => {
 88→                    vvco_err!(output, "jjx_nominate: error: {}", e);
 89→                    return (1, output.vvco_finish());
 90→                }
 91→            }
 92→
 93→            vvco_out!(output, "{}", result.firemark);
 94→            (0, output.vvco_finish())
 95→        }
 96→        Err(e) => {
 97→            vvco_err!(output, "jjx_nominate: error: {}", e);
 98→            (1, output.vvco_finish())
 99→        }
100→    }

