  5→//! Rail command - reorder Paces within a Heat
  6→//!
  7→//! Supports two modes:
  8→//! - Order mode: replace entire sequence with provided order array
  9→//! - Move mode: relocate a single pace using positioning flags
 10→
 11→use clap::Args;
 12→use std::path::PathBuf;
 13→
 14→use vvc::{vvco_out, vvco_err};
 15→
 16→use crate::jjrf_favor::jjrf_Firemark as Firemark;
 17→use crate::jjrg_gallops::jjrg_Gallops as Gallops;
 18→
 19→/// Arguments for jjx_rail command
 20→#[derive(Args, Debug)]
 21→pub struct jjrrl_RailArgs {
 22→    /// Path to the Gallops JSON file
 23→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
 24→    pub file: PathBuf,
 25→
 26→    /// Target Heat identity (Firemark)
 27→    pub firemark: String,
 28→
 29→    /// Legacy positional args - rejected at runtime
 30→    #[arg(trailing_var_arg = true)]
 31→    pub order: Vec<String>,
 32→
 33→    // Move mode arguments
 34→
 35→    /// Coronet to relocate within order - triggers move mode
 36→    #[arg(long, short = 'm')]
 37→    pub r#move: Option<String>,
 38→
 39→    /// Move before specified Coronet
 40→    #[arg(long, conflicts_with_all = ["after", "first", "last"])]
 41→    pub before: Option<String>,
 42→
 43→    /// Move after specified Coronet
 44→    #[arg(long, conflicts_with_all = ["before", "first", "last"])]
 45→    pub after: Option<String>,
 46→
 47→    /// Move to beginning of order
 48→    #[arg(long, conflicts_with_all = ["before", "after", "last"])]
 49→    pub first: bool,
 50→
 51→    /// Move to end of order
 52→    #[arg(long, conflicts_with_all = ["before", "after", "first"])]
 53→    pub last: bool,
 54→}
 55→
 56→/// Execute rail command - reorder Paces within a Heat
 57→pub fn jjrrl_run_rail(args: jjrrl_RailArgs) -> (i32, String) {
 58→    use crate::jjrg_gallops::jjrg_RailArgs as LibRailArgs;
 59→    use crate::jjrn_notch::{jjrn_HeatAction, jjrn_format_heat_message};
 60→
 61→    let mut output = vvc::vvco_Output::buffer();
 62→
 63→    // Acquire lock FIRST - fail fast if another operation is in progress
 64→    let lock = match vvc::vvcc_CommitLock::vvcc_acquire() {
 65→        Ok(l) => l,
 66→        Err(e) => {
 67→            vvco_err!(output, "jjx_rail: error: {}", e);
 68→            return (1, output.vvco_finish());
 69→        }
 70→    };
 71→
 72→    let order: Vec<String> = if args.order.len() == 1 && args.order[0].starts_with('[') {
 73→        match serde_json::from_str(&args.order[0]) {
 74→            Ok(v) => v,
 75→            Err(_) => args.order.clone(),
 76→        }
 77→    } else {
 78→        args.order.clone()
 79→    };
 80→
 81→    let mut gallops = match Gallops::jjrg_load(&args.file) {
 82→        Ok(g) => g,
 83→        Err(e) => {
 84→            vvco_err!(output, "jjx_rail: error loading Gallops: {}", e);
 85→            return (1, output.vvco_finish());
 86→        }
 87→    };
 88→
 89→    let firemark = args.firemark.clone();
 90→    let move_coronet = args.r#move.clone();
 91→    let move_before = args.before.clone();
 92→    let move_after = args.after.clone();
 93→    let move_first = args.first;
 94→    let move_last = args.last;
 95→
 96→    // Capture old order for no-op detection
 97→    let fm = Firemark::jjrf_parse(&firemark).expect("rail given invalid firemark");
 98→    let old_order: Vec<String> = gallops.heats.get(&fm.jjrf_display())
 99→        .map(|h| h.order.clone())
100→        .unwrap_or_default();
101→
102→    let rail_args = LibRailArgs {
103→        firemark: args.firemark,
104→        order,
105→        move_coronet: args.r#move,
106→        before: args.before,
107→        after: args.after,
108→        first: args.first,
109→        last: args.last,
110→    };
111→
112→    match gallops.jjrg_rail(rail_args) {
113→        Ok(new_order) => {
114→            // No-op detection: if order unchanged, exit 0 with message
115→            if new_order == old_order {
116→                let position = if move_first { "first" }
117→                    else if move_last { "last" }
118→                    else if move_before.is_some() { "requested position" }
119→                    else if move_after.is_some() { "requested position" }
120→                    else { "requested position" };
121→                let coronet_display = move_coronet.as_deref().unwrap_or("pace");
122→                vvco_out!(output, "jjx_rail: no change — {} is already {}", coronet_display, position);
123→                for coronet in new_order {
124→                    vvco_out!(output, "{}", coronet);
125→                }
126→                return (0, output.vvco_finish());
127→            }
128→
129→            // Compute descriptive subject for commit message
130→            let subject = if let Some(ref moved) = move_coronet {
131→                // Move mode: describe where the pace was moved
132→                let target = if move_first { "to first".to_string() }
133→                    else if move_last { "to last".to_string() }
134→                    else if let Some(ref b) = move_before { format!("before {}", b) }
135→                    else if let Some(ref a) = move_after { format!("after {}", a) }
136→                    else { "???".to_string() };
137→                format!("moved {} {}", moved, target)
138→            } else {
139→                // Order mode: list the new order
140→                format!("order: {}", new_order.join(", "))
141→            };
142→
143→            let message = jjrn_format_heat_message(&fm, jjrn_HeatAction::Rail, &subject);
144→
145→            match crate::jjri_io::jjri_persist(&lock, &gallops, &args.file, &fm, message, 50000, &mut output) {
146→                Ok(hash) => {
147→                    vvco_out!(output, "jjx_rail: committed {}", &hash[..8]);
148→                }
149→                Err(e) => {
150→                    vvco_err!(output, "jjx_rail: error: {}", e);
151→                    return (1, output.vvco_finish());
152→                }
153→            }
154→
155→            for coronet in new_order {
156→                vvco_out!(output, "{}", coronet);
157→            }
158→            (0, output.vvco_finish())
159→        }
160→        Err(e) => {
161→            vvco_err!(output, "jjx_rail: error: {}", e);
162→            (1, output.vvco_finish())
163→        }
164→    }
165→    // lock released here
166→}
