  5→//! Draft command - move a Pace from one Heat to another
  6→//!
  7→//! Implements the jjx_draft subcommand and related structures.
  8→
  9→use clap::Args;
 10→use std::path::PathBuf;
 11→
 12→use vvc::{vvco_out, vvco_err, vvco_Output};
 13→
 14→use crate::jjrf_favor::jjrf_Firemark as Firemark;
 15→use crate::jjrg_gallops::jjrg_Gallops as Gallops;
 16→use crate::jjri_io::jjri_paddock_path;
 17→use crate::jjrn_notch::{jjrn_HeatAction as HeatAction, jjrn_format_heat_message as format_heat_message};
 18→
 19→/// Arguments for jjx_draft command
 20→#[derive(Args, Debug)]
 21→pub struct jjrdr_DraftArgs {
 22→    /// Path to the Gallops JSON file
 23→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
 24→    pub file: PathBuf,
 25→
 26→    /// Pace identity to move (Coronet)
 27→    pub coronet: String,
 28→
 29→    /// Destination Heat identity (Firemark)
 30→    #[arg(long)]
 31→    pub to: String,
 32→
 33→    /// Insert before specified Coronet in destination
 34→    #[arg(long, conflicts_with_all = ["after", "first"])]
 35→    pub before: Option<String>,
 36→
 37→    /// Insert after specified Coronet in destination
 38→    #[arg(long, conflicts_with_all = ["before", "first"])]
 39→    pub after: Option<String>,
 40→
 41→    /// Insert at beginning of destination Heat
 42→    #[arg(long, conflicts_with_all = ["before", "after"])]
 43→    pub first: bool,
 44→}
 45→
 46→/// Handler function for draft command
 47→pub fn jjrdr_run_draft(args: jjrdr_DraftArgs) -> (i32, String) {
 48→    use crate::jjrg_gallops::jjrg_DraftArgs as LibDraftArgs;
 49→    let mut output = vvco_Output::buffer();
 50→
 51→    // Acquire lock FIRST - fail fast if another operation is in progress
 52→    let lock = match vvc::vvcc_CommitLock::vvcc_acquire() {
 53→        Ok(l) => l,
 54→        Err(e) => {
 55→            vvco_err!(output, "jjx_draft: error: {}", e);
 56→            return (1, output.vvco_finish());
 57→        }
 58→    };
 59→
 60→    let mut gallops = match Gallops::jjrg_load(&args.file) {
 61→        Ok(g) => g,
 62→        Err(e) => {
 63→            vvco_err!(output, "jjx_draft: error loading Gallops: {}", e);
 64→            return (1, output.vvco_finish());
 65→        }
 66→    };
 67→
 68→    let coronet = args.coronet.clone();
 69→    let to = args.to.clone();
 70→    let draft_args = LibDraftArgs {
 71→        coronet: args.coronet,
 72→        to: args.to,
 73→        before: args.before,
 74→        after: args.after,
 75→        first: args.first,
 76→    };
 77→
 78→    match gallops.jjrg_draft(draft_args) {
 79→        Ok(result) => {
 80→            // Save gallops
 81→            if let Err(e) = gallops.jjrg_save(&args.file) {
 82→                vvco_err!(output, "jjx_draft: error saving Gallops: {}", e);
 83→                return (1, output.vvco_finish());
 84→            }
 85→
 86→            // Commit using machine_commit - draft affects source and dest paddocks
 87→            // Parse both firemarks to get paddock paths
 88→            let src_coronet = crate::jjrf_favor::jjrf_Coronet::jjrf_parse(&coronet)
 89→                .expect("draft given invalid source coronet");
 90→            let src_fm = src_coronet.jjrf_parent_firemark();
 91→            let dest_fm = Firemark::jjrf_parse(&to).expect("draft given invalid destination firemark");
 92→
 93→            let gallops_path = args.file.to_string_lossy().to_string();
 94→            let src_paddock_path = jjri_paddock_path(src_fm.jjrf_as_str());
 95→            let dest_paddock_path = jjri_paddock_path(dest_fm.jjrf_as_str());
 96→
 97→            let commit_args = vvc::vvcm_CommitArgs {
 98→                files: vec![
 99→                    gallops_path,
100→                    src_paddock_path,
101→                    dest_paddock_path,
102→                ],
103→                message: format_heat_message(&dest_fm, HeatAction::Draft, &format!("{} → {}", coronet, result.new_coronet)),
104→                size_limit: 50000,
105→                warn_limit: 30000,
106→            };
107→
108→            match vvc::machine_commit(&lock, &commit_args, &mut output) {
109→                Ok(hash) => {
110→                    vvco_out!(output, "jjx_draft: committed {}", &hash[..8]);
111→                }
112→                Err(e) => {
113→                    vvco_err!(output, "jjx_draft: commit warning: {}", e);
114→                }
115→            }
116→
117→            vvco_out!(output, "{}", result.new_coronet);
118→            (0, output.vvco_finish())
119→        }
120→        Err(e) => {
121→            vvco_err!(output, "jjx_draft: error: {}", e);
122→            (1, output.vvco_finish())
123→        }
124→    }
125→    // lock released here
126→}
